// // This module implements a 16-bit down counter with enable and reset functionality. The counter should decrement on every clock cycle when enabled. If the reset signal is asserted, the counter should reset to zero.
module counter_16bit (
    input clk,
    input rst_n,
    input en,
    output reg [15:0] count
);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count <= 16'b0;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
